  1	import * as React from 'react';
  2	import {
  3	  Button,
  4	  InputGroup,
  5	  TextInput,
  6	  ButtonVariant,
  7	  InputGroupItem,
  8	  Dropdown,
  9	  DropdownList,
 10	  DropdownItem,
 11	  MenuToggleElement,
 12	  MenuToggle
 13	} from '@patternfly/react-core';
 14	import { ServiceOverview } from '../../../types/ServiceList';
 15	import { getServicePort } from '../../../types/ServiceInfo';
 16	import { kialiStyle } from 'styles/StyleUtils';
 17	
 18	type K8sFilterBuilderProps = {
 19	  filterType: string;
 20	  headerName: string;
 21	  headerOp: string;
 22	  headerValue: string;
 23	  hostName: string;
 24	  isValid: boolean;
 25	  onAddFilter: () => void;
 26	  onHeaderNameChange: (headerName: string) => void;
 27	  onHeaderValueChange: (headerValue: string) => void;
 28	  onHostNameChange: (hostName: string) => void;
 29	  onPortValueChange: (portValue: string) => void;
 30	  onSelectFilterType: (filterType: string) => void;
 31	  onSelectHeaderOp: (headerOp: string) => void;
 32	  onSelectSchemeOp: (schemeOp: string) => void;
 33	  onSelectServiceOp: (serviceOp: string) => void;
 34	  onSelectStatusCodeOp: (statusCodeOp: string) => void;
 35	  portValue: string;
 36	  protocol: string;
 37	  schemeOp: string;
 38	  serviceOp: string;
 39	  statusCodeOp: string;
 40	  subServices: ServiceOverview[];
 41	};
 42	
 43	export const REQ_MOD = 'requestHeaderModifier';
 44	export const RESP_MOD = 'responseHeaderModifier';
 45	export const REQ_MIR = 'requestMirror';
 46	export const REQ_RED = 'requestRedirect';
 47	export const URL_REW = 'URLRewrite';
 48	export const EXT_REF = 'extensionRef';
 49	
 50	export const HTTP = 'HTTP';
 51	export const GRPC = 'GRPC';
 52	export const HTTPS = 'https';
 53	
 54	export const SC301 = '301';
 55	export const SC302 = '302';
 56	
 57	const filterOptions = {
 58	  [HTTP]: [REQ_MOD, RESP_MOD, REQ_RED, REQ_MIR],
 59	  [GRPC]: [REQ_MOD, RESP_MOD, REQ_MIR]
 60	};
 61	const schemeOptions: string[] = [HTTP, HTTPS];
 62	const statusOptions: string[] = [SC301, SC302];
 63	
 64	export const SET = 'set';
 65	export const ADD = 'add';
 66	export const REMOVE = 'remove';
 67	
 68	const allOptions = {
 69	  [REQ_MOD]: [SET, ADD, REMOVE],
 70	  [RESP_MOD]: [SET, ADD, REMOVE]
 71	};
 72	
 73	const addFilterStyle = kialiStyle({
 74	  marginLeft: 'auto'
 75	});
 76	
 77	export const K8sFilterBuilder: React.FC<K8sFilterBuilderProps> = (props: K8sFilterBuilderProps) => {
 78	  const [isFilterDropdown, setIsFilterDropdown] = React.useState<boolean>(false);
 79	  const [isHeaderDropdown, setIsHeaderDropdown] = React.useState<boolean>(false);
 80	  const [isSchemeDropdown, setIsSchemeDropdown] = React.useState<boolean>(false);
 81	  const [isStatusCodeDropdown, setIsStatusCodeDropdown] = React.useState<boolean>(false);
 82	  const [isServiceDropdown, setIsServiceDropdown] = React.useState<boolean>(false);
 83	
 84	  const renderFilterOptions: string[] = allOptions[props.filterType];
 85	
 86	  return (
 87	    <InputGroup>
 88	      <InputGroupItem>
 89	        <Dropdown
 90	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 91	            <MenuToggle
 92	              ref={toggleRef}
 93	              onClick={() => setIsFilterDropdown(!isFilterDropdown)}
 94	              data-test={'filtering-type-toggle'}
 95	              isExpanded={isFilterDropdown}
 96	            >
 97	              {props.filterType}
 98	            </MenuToggle>
 99	          )}
100	          isOpen={isFilterDropdown}
101	          onOpenChange={(isOpen: boolean) => setIsFilterDropdown(isOpen)}
102	        >
103	          <DropdownList>
104	            {filterOptions[props.protocol].map((mode, index) => (
105	              <DropdownItem
106	                key={`${mode}_${index}`}
107	                value={mode}
108	                component="button"
109	                onClick={() => {
110	                  props.onSelectFilterType(mode);
111	                  setIsFilterDropdown(!isFilterDropdown);
112	                }}
113	                data-test={`filtering-type-${mode}`}
114	              >
115	                {mode}
116	              </DropdownItem>
117	            ))}
118	          </DropdownList>
119	        </Dropdown>
120	      </InputGroupItem>
121	
122	      {(props.filterType === REQ_MOD || props.filterType === RESP_MOD) && (
123	        <Dropdown
124	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
125	            <MenuToggle
126	              ref={toggleRef}
127	              onClick={() => setIsHeaderDropdown(!isHeaderDropdown)}
128	              data-test={'header-type-toggle'}
129	              isExpanded={isHeaderDropdown}
130	            >
131	              {props.headerOp}
132	            </MenuToggle>
133	          )}
134	          isOpen={isHeaderDropdown}
135	          onOpenChange={(isOpen: boolean) => setIsHeaderDropdown(isOpen)}
136	        >
137	          <DropdownList>
138	            {renderFilterOptions.map((op, index) => (
139	              <DropdownItem
140	                key={`${op}_${index}`}
141	                value={op}
142	                component="button"
143	                onClick={() => {
144	                  props.onSelectHeaderOp(op);
145	                  setIsHeaderDropdown(!isHeaderDropdown);
146	                }}
147	                data-test={`header-type-${op}`}
148	              >
149	                {op}
150	              </DropdownItem>
151	            ))}
152	          </DropdownList>
153	        </Dropdown>
154	      )}
155	
156	      {(props.filterType === REQ_MOD || props.filterType === RESP_MOD) && (
157	        <TextInput
158	          id="filter-header-name-id"
159	          value={props.headerName}
160	          onChange={(_, value) => props.onHeaderNameChange(value)}
161	          placeholder="Header name..."
162	        />
163	      )}
164	
165	      {(props.filterType === REQ_MOD || props.filterType === RESP_MOD) && props.headerOp !== REMOVE && (
166	        <TextInput
167	          id="filter-header-value-id"
168	          value={props.headerValue}
169	          onChange={(_, value) => props.onHeaderValueChange(value)}
170	          placeholder="Header Value..."
171	        />
172	      )}
173	
174	      {props.filterType === REQ_RED && (
175	        <Dropdown
176	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
177	            <MenuToggle
178	              ref={toggleRef}
179	              onClick={() => setIsSchemeDropdown(!isSchemeDropdown)}
180	              data-test={'scheme-toggle'}
181	              isExpanded={isSchemeDropdown}
182	            >
183	              {props.schemeOp}
184	            </MenuToggle>
185	          )}
186	          isOpen={isSchemeDropdown}
187	          onOpenChange={(isOpen: boolean) => setIsSchemeDropdown(isOpen)}
188	        >
189	          <DropdownList>
190	            {schemeOptions.map((op, index) => (
191	              <DropdownItem
192	                key={`${op}_${index}`}
193	                value={op}
194	                component="button"
195	                onClick={() => {
196	                  props.onSelectSchemeOp(op);
197	                  setIsSchemeDropdown(!isSchemeDropdown);
198	                }}
199	                data-test={`scheme-${op}`}
200	              >
201	                {op}
202	              </DropdownItem>
203	            ))}
204	          </DropdownList>
205	        </Dropdown>
206	      )}
207	
208	      {props.filterType === REQ_RED && (
209	        <TextInput
210	          id="hostname"
211	          value={props.hostName}
212	          onChange={(_, value) => props.onHostNameChange(value)}
213	          placeholder="Hostname..."
214	        />
215	      )}
216	
217	      {props.filterType === REQ_RED && (
218	        <TextInput
219	          id="portValue"
220	          value={props.portValue}
221	          onChange={(_, value) => props.onPortValueChange(value)}
222	          placeholder="Port..."
223	        />
224	      )}
225	
226	      {props.filterType === REQ_RED && (
227	        <Dropdown
228	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
229	            <MenuToggle
230	              ref={toggleRef}
231	              onClick={() => setIsStatusCodeDropdown(!isStatusCodeDropdown)}
232	              data-test={'status-code'}
233	              isExpanded={isStatusCodeDropdown}
234	            >
235	              {props.statusCodeOp}
236	            </MenuToggle>
237	          )}
238	          isOpen={isStatusCodeDropdown}
239	          onOpenChange={(isOpen: boolean) => setIsStatusCodeDropdown(isOpen)}
240	        >
241	          <DropdownList>
242	            {statusOptions.map((op, index) => (
243	              <DropdownItem
244	                key={`${op}_${index}`}
245	                value={op}
246	                component="button"
247	                onClick={() => {
248	                  props.onSelectStatusCodeOp(op);
249	                  setIsStatusCodeDropdown(!isStatusCodeDropdown);
250	                }}
251	                data-test={`status-code-${op}`}
252	              >
253	                {op}
254	              </DropdownItem>
255	            ))}
256	          </DropdownList>
257	        </Dropdown>
258	      )}
259	
260	      {props.filterType === REQ_MIR && (
261	        <Dropdown
262	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
263	            <MenuToggle
264	              ref={toggleRef}
265	              onClick={() => setIsServiceDropdown(!isServiceDropdown)}
266	              data-test={'service'}
267	              isExpanded={isServiceDropdown}
268	            >
269	              {props.serviceOp}
270	            </MenuToggle>
271	          )}
272	          isOpen={isServiceDropdown}
273	          onOpenChange={(isOpen: boolean) => setIsServiceDropdown(isOpen)}
274	        >
275	          <DropdownList>
276	            {props.subServices.map((so, index) => (
277	              <DropdownItem
278	                key={`${so.name}_${index}`}
279	                value={`${so.name}:${getServicePort(so.ports)}`}
280	                component="button"
281	                onClick={() => {
282	                  props.onSelectServiceOp(`${so.name}:${getServicePort(so.ports)}`);
283	                  setIsServiceDropdown(!isServiceDropdown);
284	                }}
285	                data-test={`service-${so.name}`}
286	              >
287	                {`${so.name}:${getServicePort(so.ports)}`}
288	              </DropdownItem>
289	            ))}
290	          </DropdownList>
291	        </Dropdown>
292	      )}
293	
294	      <InputGroupItem className={addFilterStyle}>
295	        <Button
296	          variant={ButtonVariant.secondary}
297	          isDisabled={!props.isValid}
298	          onClick={props.onAddFilter}
299	          data-test="add-filter"
300	        >
301	          Add Filter
302	        </Button>
303	      </InputGroupItem>
304	    </InputGroup>
305	  );
306	};

